-- ============================================================
-- Этап 2 «Пол» (floor) проекта Homesteader's Cabin — эталонный
-- контент из ЭТАП2_Пол.md («для бабушки», реальные данные:
-- рама 3,66×7,32, балки 50×250 шаг 610 мм, фанера 18 мм шпунт;
-- шаг утепления добавлен для РФ). Скрипт покупки пиломатериала —
-- в hint шага настила (шаг 4).
-- Идемпотентно: пересоздаёт только шаги этапа floor (id ...312);
-- Этапы 0–1 и остальные не трогает. Без этапа 312 — тихо пропуск.
-- ============================================================

do $do$
begin
  if not exists (select 1 from stages
                 where id = 'de300000-0000-4000-8000-000000000312') then
    return;
  end if;

  update stages set intro = '🟫 Это наш первый «жёлто-коричневый» этап. Опоры готовы, балки лежат — теперь строим на них раму пола: как деревянную решётку, поверх которой ляжет настил. По этому полу ты будешь ходить, на нём встанут стены.

Главное правило этого этапа — ровность и прямые углы. Кривой пол = кривые стены = кривой дом. Поэтому будем много проверять уровнем и рулеткой. Это не сложно, просто аккуратно.

Займёт примерно 3 дня. Тебе понадобится помощник — доски длинные, одному тяжело. Но сама работа приятная: впервые увидишь очертания своего будущего дома в натуральную величину. Встанешь на готовый пол — и поймёшь: «вот тут будет моя кухня, а тут гостиная».'
  where id = 'de300000-0000-4000-8000-000000000312';

  delete from steps where stage_id = 'de300000-0000-4000-8000-000000000312';

  insert into steps (id, stage_id, sort, title, why_text, prep_text, actions, tools,
    self_check, hint, common_mistake, helpers_needed) values
  ('de300000-0000-4000-8000-000000000431',
   'de300000-0000-4000-8000-000000000312', 1,
   'Собираем внешнюю раму пола',
   'Сначала собираем «периметр» — прямоугольную рамку из толстых досок по краю. Это скелет, к которому потом крепятся все остальные балки. От того, насколько ровный этот прямоугольник, зависит весь дом.',
   'Купи заранее (из сметы): доски 50×250 мм (2×10) на раму — длинные, по размеру дома; гвозди/саморезы для каркаса (90-100 мм).',
   '["Дом у нас 3,66 м в ширину и 7,32 м в длину. Выложи по краю опорных балок (которые уложил в Этапе 1) доски 50×250 «на ребро» — они образуют прямоугольную рамку.","Соедини углы: приставь торец одной доски к боку другой, скрути саморезами или сбей гвоздями. По 3-4 крепежа в каждый угол.","Проверь диагонали! Измерь рамку из угла в угол крест-накрест. Обе диагонали должны совпасть (разница ≤5 мм) — тогда прямоугольник ровный. Если не совпали — двигай раму, пока не сравняются.","Прикрути раму к опорным балкам снизу."]',
   '{"шуруповёрт или молоток","рулетка 10 м","угольник","уровень","карандаш"}',
   '["Рама 3,66 × 7,32 м собрана, доски на ребре","Углы скреплены (3-4 крепежа каждый)","Диагонали совпали (разница ≤5 мм)","Рама прикручена к опорным балкам"]',
   'Доски 50×250 длинные и тяжёлые. Ставь их на ребро (высокой стороной вверх) — так они держат нагрузку. Плашмя класть нельзя, прогнутся.',
   'Не проверить диагонали и погнать дальше. Перекос в раме пола потом «поедет» вверх — стены не сойдутся, крыша будет кривой. 5 минут на диагонали спасают недели переделок.',
   0),
  ('de300000-0000-4000-8000-000000000432',
   'de300000-0000-4000-8000-000000000312', 2,
   'Ставим балки пола (лаги)',
   'Внутри рамы через равные промежутки ставим поперечные балки — их называют лагами. Лаги — это балки пола, на которые ляжет настил. Чем чаще лаги, тем крепче пол, тем меньше он «играет» под ногами.',
   'Купи заранее: доски 50×250 мм — на лаги, длиной по ширине дома (~3,5 м между рамой); металлические подвесы для балок (упрощают крепёж) — по числу лаг × 2; саморезы для подвесов.',
   '["Размечай на раме места лаг: они ставятся через каждые 61 см (это шаг 610 мм — стандарт, доски настила ровно лягут). Отметь карандашом на обеих длинных сторонах рамы.","Вставляй лаги 50×250 поперёк, между длинными сторонами рамы, точно по меткам. Ставь их на ребро, вровень с верхом рамы.","Закрепи каждую лагу подвесами или гвоздями наискосок (по 2 с каждого конца).","Проверь уровнем, что все лаги вровень — по ним пойдёт ровный настил."]',
   '{"рулетка 10 м","карандаш","уровень","шуруповёрт или молоток"}',
   '["Лаги размечены через 61 см","Все лаги вставлены и закреплены (по 2 крепежа с концов)","Лаги вровень с верхом рамы (проверено уровнем)"]',
   'Шаг 61 см выбран не случайно — это чтобы стандартный лист фанеры (122 см) лёг ровно краями на лаги. Не меняй шаг, иначе настил повиснет в воздухе.',
   'Ставить лаги «примерно», на глаз. Тогда край фанеры попадёт мимо лаги, пол будет прогибаться. Меряй каждую по метке.',
   0),
  ('de300000-0000-4000-8000-000000000433',
   'de300000-0000-4000-8000-000000000312', 3,
   'Утепляем пол (важно для России!)',
   'Между лагами укладываем утеплитель — иначе через пол будет тянуть холодом снизу, а зимой пол будет ледяным. В США этот дом строят без утепления (тёплый климат), но для нас это обязательно.',
   'Купи заранее: утеплитель (минеральная вата) толщиной ~200 мм — по площади пола; ветро-влагозащитная плёнка (снизу), пароизоляция (сверху); черновые доски/бруски для поддержки утеплителя снизу.',
   '["Снизу к лагам подшей ветрозащитную плёнку и черновые бруски — на них ляжет утеплитель, чтобы не выпал.","Уложи плиты минваты между лагами плотно, без щелей (в щели уходит тепло). Толщина примерно вровень с лагами (~200 мм).","Сверху накрой пароизоляционной плёнкой (не даёт влаге из дома мочить утеплитель), стыки проклей."]',
   '{"степлер","нож"}',
   '["Снизу подшита защита, утеплитель не выпадает","Минвата уложена плотно, без щелей (~200 мм)","Сверху пароизоляция, стыки проклеены"]',
   'Утеплитель кроит легко — обычным ножом или ножовкой. Режь чуть шире промежутка (на 1-2 см), чтоб вставал враспор и не оставлял щелей.',
   'Щели между плитами утеплителя и класть «дырявый» утеплитель. Даже маленькие щели = мостики холода, пол будет холодным. Укладывай плотно, встык.',
   0),
  ('de300000-0000-4000-8000-000000000434',
   'de300000-0000-4000-8000-000000000312', 4,
   'Настилаем пол (фанера)',
   'Поверх лаг и утеплителя кладём листы фанеры — это и есть черновой пол, по которому будешь ходить. На него потом ляжет чистовое покрытие (ламинат, доска).',
   'Купи заранее: фанера шпунтованная ¾ дюйма (~18 мм) — листы 122×244 см (в оригинале 8 листов + 2 половинки); саморезы по дереву 40-50 мм; клей для дерева (по желанию, для тишины пола).',
   '["Начинай с угла. Клади первый лист фанеры на лаги, край листа должен попадать на середину лаги (чтобы соседний лист тоже на неё опёрся).","Шпунтованная фанера соединяется «в замок» (паз-гребень) — стыкуй листы плотно, без зазоров.","Прикручивай фанеру к лагам саморезами каждые 20 см по всем лагам. Можно промазать лаги клеем перед укладкой — пол не будет скрипеть.","Раскладывай листы с разбежкой швов — как кирпичная кладка, чтобы стыки не совпадали в линию (так пол крепче)."]',
   '{"шуруповёрт"}',
   '["Листы легли краями на середину лаг","Стыки плотные (шпунт в замок)","Прикручено каждые 20 см по лагам","Швы вразбежку (не в одну линию)"]',
   '«Шпунтованная» значит с замком по краям (паз и гребень) — листы защёлкиваются друг в друга, пол получается монолитным, без щелей. Обычную фанеру брать не стоит — будут зазоры.

СКРИПТ — покупка пиломатериала на пол (доски 50×250 и фанера). На доске 50×250 (это дорогая крупная доска) и на фанере часто обманывают — на влажности, сорте, кубатуре. Спрашивай про доски 50×250: «Естественной влажности или сухая?» — для лаг пола лучше сухая (не поведёт под нагрузкой), естественной влажности дешевле, но может «крутить»; «Сорт 1 или 2?» — для несущих лаг только 1-2 сорт, без крупных сучков и трещин; «Посчитайте кубатуру при мне». Спрашивай про фанеру: «Шпунтованная (с замком) или обычная?» — нам нужна шпунтованная для пола; «Какой сорт и влагостойкость?» — для пола ФК или ФСФ, толщина 18 мм. Красные флаги: доски синие, чёрные пятна, плесень — гнилой товар, не бери; «влажность нормальная, не парься» — значит сырая, лаги поведёт; «кубатуру на глаз» — обвесят. Проверка кубатуры доски 50×250: одна доска 6 м × 0,25 м × 0,05 м = 0,075 м³, значит в 1 кубе таких досок 1 ÷ 0,075 ≈ 13 досок. Дают меньше за «куб» — считай при них. Ориентир: доска 50×250 дороже обычной (широкая). Фанера 18 мм шпунт — от ~1500-2000 ₽ за лист (уточняй в регионе).',
   'Класть листы стык-в-стык в одну линию (без разбежки). Тогда по линии стыков пол слабый. Смещай ряды, как кирпичи.',
   0);
end
$do$;
